#include <bits/stdc++.h>
using namespace std;
#define int long long
#define N 100005
#define MOD 1000000007
#define INF 1e18
#define PI acos(-1)
#define endl "\n"
#define F first
#define S second
#define MP make_pair

int n, k;

int32_t main()
{
	ios::sync_with_stdio(false);
	cin.tie(0);
	cout.tie(0);

	cin >> k;
	int cnt = 0;
	while (k)
	{
		cnt++;
		k /= 2;
	}
	n = 1 << cnt;
	cout << string(n, 'c') + string(n, 'e') + string(n, 'f') + string(n, 'o') + string(n, 'r') + string(n, 's') << endl;

	return 0;
}
